-- ============================================================
-- 关联数据: 支付方式 (每个房间配2-3种)
-- ============================================================
INSERT INTO room_payment (room_id, payment_type_id)
SELECT r.id, p.id FROM room_info r CROSS JOIN payment_type p
WHERE p.sort_order <= 3 AND r.deleted = 0;

-- ============================================================
-- 关联数据: 租期 (每个房间配3-4种)
-- ============================================================
INSERT INTO room_lease_term (room_id, lease_term_id)
SELECT r.id, t.id FROM room_info r CROSS JOIN lease_term t
WHERE t.sort_order <= 4 AND r.deleted = 0;

-- ============================================================
-- 关联数据: 标签 (随机分配2-4个标签)
-- ============================================================
INSERT INTO room_label (room_id, label_id)
SELECT r.id, l.id FROM room_info r CROSS JOIN label_info l
WHERE MOD(r.id + l.id, 3) = 0 AND r.deleted = 0;

-- 确保每个房间至少有2个标签
INSERT IGNORE INTO room_label (room_id, label_id)
SELECT r.id, 1 FROM room_info r WHERE r.deleted = 0;
INSERT IGNORE INTO room_label (room_id, label_id)
SELECT r.id, 3 FROM room_info r WHERE r.deleted = 0;

-- ============================================================
-- 关联数据: 配套 (每个房间配4-6个基础配套)
-- ============================================================
INSERT INTO room_facility (room_id, facility_id)
SELECT r.id, f.id FROM room_info r CROSS JOIN facility_info f
WHERE f.sort_order <= 5 AND r.deleted = 0;

-- ============================================================
-- 验证
-- ============================================================
SELECT '公寓' AS 类型, COUNT(*) AS 数量 FROM apartment_info WHERE deleted=0
UNION ALL SELECT '房间', COUNT(*) FROM room_info WHERE deleted=0
UNION ALL SELECT '支付关联', COUNT(*) FROM room_payment WHERE deleted=0
UNION ALL SELECT '租期关联', COUNT(*) FROM room_lease_term WHERE deleted=0
UNION ALL SELECT '标签关联', COUNT(*) FROM room_label WHERE deleted=0
UNION ALL SELECT '配套关联', COUNT(*) FROM room_facility WHERE deleted=0;

-- 检查每个区是否都有房间
SELECT d.name AS 区域, COUNT(ri.id) AS 房间数
FROM district_info d
LEFT JOIN apartment_info ai ON ai.district_id = d.id AND ai.deleted = 0
LEFT JOIN room_info ri ON ri.apartment_id = ai.id AND ri.deleted = 0
WHERE d.level = 'district'
GROUP BY d.id, d.name
ORDER BY d.id;
